// Build Video Result — Apify flow with native n8n polling
const pickData = $('Extract Video Data').first().json;
const statusData = $('Check Apify Status').first().json;
const resultsIn = $input.first().json;

const pollStatus = (statusData && statusData.data && statusData.data.status) || '';
const TERMINAL = ['SUCCEEDED','FAILED','ABORTED','TIMED-OUT','TIMED_OUT'];
const terminalReached = TERMINAL.includes(pollStatus);
const apifySucceeded = (pollStatus === 'SUCCEEDED');

let storageUrl = '';
let success = false;
let fileSize = 0;
let duration = 0;
let apifyTitle = '';
let errorReason = '';

if (!terminalReached) {
  errorReason = 'apify_run_timeout';
} else if (!apifySucceeded) {
  errorReason = 'apify_run_' + String(pollStatus || 'unknown').toLowerCase();
} else {
  const arr = Array.isArray(resultsIn)
    ? resultsIn
    : (resultsIn && Array.isArray(resultsIn.data) ? resultsIn.data : [resultsIn]);
  const item = arr && arr[0];
  if (item && typeof item === 'object') {
    storageUrl = item.storageUrl || item.downloadUrl || '';
    success = !!((item.status === 'completed' || item.success === true) && storageUrl);
    fileSize = item.fileSizeBytes || item.fileSize || 0;
    duration = item.duration || 0;
    apifyTitle = item.title || '';
    if (!success) errorReason = 'apify_no_storage_url';
  } else {
    errorReason = 'apify_empty_dataset';
  }
}

return [{ json: {
  ...pickData,
  videoStorageUrl: success ? storageUrl : '',
  videoStored: success,
  videoFileSize: fileSize,
  clipDuration: duration,
  fullDuration: duration,
  viralHook: '',
  clipReason: '',
  transcriptExcerpt: '',
  apifyTitle: apifyTitle,
  hasTranscript: false,
  errorReason: errorReason
}}];

parameters.jsonBody:
={{ (() => {
  const d = $('Upload to Publer Media').first().json;
  const mediaId = d.publerMediaId;
  const thumbs = d.publerThumbnails || [];
  const text = d.caption;
  const firstComment = d.firstComment || '';
  const fbId = '69d03eb8d8776303e3535e30';

  const commentObj = firstComment ? [{ text: firstComment, delay: { duration: 0, unit: 'Minute' } }] : [];

  if (mediaId) {
    const thumbArr = thumbs.map(t => ({ id: t.id, small: t.small, real: t.real }));
    const mediaObj = {
      id: mediaId,
      thumbnails: thumbArr,
      default_thumbnail: 0
    };
    return JSON.stringify({
      bulk: {
        state: 'scheduled',
        posts: [{
          networks: {
            facebook: { type: 'video', media: [mediaObj], text: text }
          },
          accounts: [
            { id: fbId, comments: commentObj }
          ]
        }]
      }
    });
  } else {
    return JSON.stringify({ error: 'No media uploaded - pipeline should have stopped at Check Video OK' });
  }
})() }}

