  const parts = rawTitle.split('\n');
  const line1Text = (parts[0] || 'WATCH THIS').replace(/[<>&]/g, '').toUpperCase().trim();
  const line2Text = (parts[1] || '').replace(/[<>&]/g, '').toUpperCase().trim();
  const w1 = line1Text.split(/\s+/).length;
  const w2 = line2Text ? line2Text.split(/\s+/).length : 0;
  const line1Size = w1 <= 2 ? 88 : w1 <= 3 ? 76 : w1 <= 4 ? 66 : 56;
  const line2Size = w2 <= 3 ? 54 : w2 <= 5 ? 46 : w2 <= 7 ? 40 : 34;
  const fontImport = '@import url(https://fonts.googleapis.com/css2?family=Anton&display=swap);';
  const line1Style = 'font-family:Anton,Impact,sans-serif;font-size:' + line1Size + 'px;text-align:center;line-height:1.1;text-transform:uppercase;letter-spacing:2px;font-weight:400;text-shadow:4px 4px 16px rgba(0,0,0,1),0 0 50px rgba(0,0,0,0.8);padding:10px 20px;word-wrap:break-word;overflow:hidden';
  const line2Style = 'font-family:Anton,Impact,sans-serif;font-size:' + line2Size + 'px;text-align:center;line-height:1.15;text-transform:uppercase;letter-spacing:1px;font-weight:400;text-shadow:3px 3px 12px rgba(0,0,0,1),0 0 40px rgba(0,0,0,0.8);padding:10px 20px;word-wrap:break-word;overflow:hidden;color:#FFFFFF';
  const words1 = line1Text.split(' ');
  const firstWord = words1[0] || '';
  const restWords = words1.slice(1).join(' ');
  var line1Html;
  if (restWords) {
    line1Html = '<style>' + fontImport + '</style><div style=' + q + line1Style + q + '><span style=' + q + 'color:' + cfg.color + q + '>' + firstWord + '</span> <span style=' + q + 'color:#FFFFFF' + q + '>' + restWords + '</span></div>';
  } else {
    line1Html = '<style>' + fontImport + '</style><div style=' + q + line1Style + ';color:' + cfg.color + q + '>' + firstWord + '</div>';
  }
  var line2Html = '<style>' + fontImport + '</style><div style=' + q + line2Style + q + '>' + line2Text + '</div>';
  const labelStyle = 'font-family:Arial,Helvetica,sans-serif;font-size:13px;color:#FFFFFF;font-weight:800;letter-spacing:4px;text-shadow:2px 2px 10px rgba(0,0,0,1)';
