    if (clipConfidence > 1) clipConfidence = 1;
    var HARD_CAP = 25;
    if (!isNaN(startSec) && !isNaN(endSec) && endSec > startSec && startSec >= 0) {
      if (endSec - startSec > HARD_CAP) endSec = Math.round((startSec + HARD_CAP) * 10) / 10;
      selectorOk = true;
    } else { selectorError = 'Invalid timing: start=' + startSec + ' end=' + endSec; }
  } else { selectorError = 'No JSON in clip selector response'; }
} catch (e) { selectorError = 'Clip selector parse error: ' + (e && e.message); }
return [{ json: Object.assign({}, pd, { clipStart: startSec, clipEnd: endSec, clipReason: clipReason, clipEmotion: clipEmotion, clipConfidence: clipConfidence, transcriptExcerptUsed: excerptUsed, clipSelectorOk: selectorOk, clipSelectorError: selectorError }) }];

var data = $input.first().json;
var transcript = data.timestampedTranscript || '';
var fallbackExcerpt = transcript.length > 500 ? transcript.substring(0, 500) : transcript;
return [{ json: Object.assign({}, data, { clipStart: 0, clipEnd: 25, clipReason: 'FALLBACK: Clip selector failed (' + (data.clipSelectorError || 'unknown') + '). Using first 25s.', clipEmotion: 'pain', clipConfidence: 0, transcriptExcerptUsed: fallbackExcerpt, clipSelectorOk: false, clipSelectorFallback: true }) }];

var data = $input.first().json;
data.videoStorageUrl = data.originalVideoUrl || data.videoStorageUrl || '';
data.hctiThumbnailUrl = '';
data.used_fallback_thumbnail = true;
data.thumbnail_status = data.renderFailed ? 'failed' : (data.renderTimedOut ? 'skipped' : 'failed');
return [{ json: data }];

