// After a failed download, check if we should try the next queued video.
// Max 3 retries per execution to avoid infinite loops.
const staticData = $getWorkflowStaticData('global');
const execId = $execution.id;
const key = 'retryCount_' + execId;
const count = (staticData[key] || 0) + 1;
staticData[key] = count;

// Clean up stale keys from previous executions
for (const k of Object.keys(staticData)) {
  if (k.startsWith('retryCount_') && k !== key) {
    delete staticData[k];
  }
}

if (count >= 3) {
  // Tried 3 videos already, stop this execution
  return [];
}

// Pass through to fetch the next queued video
return [{ json: { retry: count, previousVideoFailed: true } }];

const input = $input.first().json;
let runId = '';
let datasetId = '';
let status = '';
try {
  if (input && input.data) {
    runId = input.data.id || '';
    datasetId = input.data.defaultDatasetId || '';
    status = input.data.status || '';
  }
} catch(e) {}
const TERMINAL = ['SUCCEEDED','FAILED','ABORTED','TIMED-OUT','TIMED_OUT'];
return [{ json: { runId, datasetId, status, isDone: TERMINAL.includes(status), succeeded: status === 'SUCCEEDED' } }];
